import { useNavigate } from "react-router-dom";
import AudioCallView from "@/pages/AudioCall/AudioCallView";
import LiveRoomTopPanel from "@/components/LiveRoomTopPanel";
import webCallManager from "@/utils/webCallManager";
import { CallState } from "@/types/call";
import { useEffect } from "react";
import { useCall } from "@/hooks/useCall";
import { getReturnPath } from "@/utils/callReturnPath";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

/**
 * AudioCall - 音频通话页面
 *
 * 参考 VideoCall 实现，主要区别是展示头像而不是视频
 *
 * 应用 Vercel 最佳实践:
 * - rerender-use-ref-transient-values: 使用 hook 管理状态
 * - rendering-conditional-render: 条件渲染使用三元运算符
 */
const AudioCall = () => {
  const navigate = useNavigate();
  const { callState } = useCall();

  const handleClose = async () => {
    // 挂断
    await webCallManager.hangup();
    // 跳转回 live
    navigate(getReturnPath(), { replace: true });
  };

  useEffect(() => {
    // 埋点：语音通话连接中页面显示
    bpTrack(EventName.pwa_voice_call_connecting_show);

    if (callState === CallState.Incoming) {
      webCallManager.accept();
    }

    if (!webCallManager?.connectSession?.roomId) {
      navigate(getReturnPath(), { replace: true });
    }
  }, [callState, navigate]);

  useEffect(() => {
    return () => {
      webCallManager.hangup();
    };
  }, []);

  return (
    <div className="fixed inset-0 bg-black">
      <AudioCallView />
      <LiveRoomTopPanel onClickClose={handleClose} isAlwaysShow={true} />
    </div>
  );
};

export default AudioCall;
